/**
 * Creates a tunnel for cross tab communication.
 * The resulting iframe should be appended to the html document, and then it can be used as a parameter to [[connect]].
 * @param {string} host Url of the SmartDesign instance. e.g. https://mycompany.com/smartdesign or http://login.smartwe.de/SmartWe/
 * @param {VoidFunction} readyCallback Callback to execute after the tunnel is established
 * @return {HTMLIFrameElement} frame element to be used for the tunneling
 */
export const createTunnel = (host = "", readyCallback: () => void): HTMLIFrameElement => {
    return createTunnelInternal(host, readyCallback);
};

export const invokeMethod = (
    domain: string,
    target: () => IEndpoint,
    source: () => IEndpoint,
    method: string,
    parameters?: any[],
): Promise<any> => {
    const communicator = new Communicator(domain, target, source);
    return communicator.invoke(method, ...(parameters || []));
};

export const expose = (
    appDomain: string,
    obj: any,
    target: () => IEndpoint,
    source: () => IEndpoint = () => window,
    timeout = 10000,
): (() => void) => {
    const handlers = getMethods(obj).map((method) => {
        const communicator = createCommunicator(appDomain, target, source, timeout);
        const messageHandlerRemover = communicator.expose(obj, method);
        return messageHandlerRemover;
    });
    return () => handlers.forEach((item) => item());
};

export const createCommunicator = <REMOTE = any>(
    appDomain: string,
    target: () => IEndpoint,
    source: () => IEndpoint = () => window,
    timeout = 10000,
): Communicator<REMOTE> => {
    return new Communicator(appDomain, target, source, timeout);
};
